import React from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faRocket, faShieldHalved, faLightbulb } from '@fortawesome/free-solid-svg-icons';
import './App.css';

const Box = ({ icon, title, items, bgColor }) => (
  <div className="card" style={{ backgroundColor: bgColor }}>
    <div className="icon-wrapper">
      <FontAwesomeIcon icon={icon} />
    </div>
    <h2 className="card-title">{title}</h2>
    <ul className="card-list">
      {items.map((item, index) => (
        <li key={index}>{item}</li>
      ))}
    </ul>
  </div>
);

function Services() {
  const data = [
    {
      title: "Strateji",
      icon: faLightbulb,
      color: "#3D3A27",
      items: ["Pazar Analizi", "Yol Haritası", "Planlama"]
    },
    {
      title: "Geliştirme",
      icon: faRocket,
      color: "#113033",
      items: ["Performans", "Modern Arayüz", "Hızlı Dağıtım"]
    },
    {
      title: "Güvenlik",
      icon: faShieldHalved,
      color: "#0E2A2D",
      items: ["Veri Koruma", "SSL Sertifikası", "7/24 İzleme"]
    }
  ];

  return (
    <div className="container">
      <div className="box-wrapper">
        {data.map((box, index) => (
          <Box 
            key={index}
            title={box.title}
            icon={box.icon}
            bgColor={box.color}
            items={box.items}
          />
        ))}
      </div>
    </div>
  );
}

export default Services;
